#[derive(Clone, PartialEq, Default, serde::Serialize, serde::Deserialize)]
#[pyclass(eq, eq_int, from_py_object)]
pub enum DiagnosticSeverity {
    #[pyo3(name = "ERROR")]
    #[default]
    Error = 0,
    #[pyo3(name = "WARNING")]
    Warning = 1,
    #[pyo3(name = "INFO")]
    Info = 2,
}
#[pymethods]
impl DiagnosticSeverity {
    #[new]
    fn __new__(value: pyo3::Bound<'_, pyo3::PyAny>) -> pyo3::PyResult<Self> {
        use pyo3::prelude::*;
        // Try to extract as string first
        if let Ok(s) = value.extract::<&str>() {
            let s_lower = s.to_lowercase();
            match s_lower.as_str() {
                "error" => return Ok(Self::Error),
                "warning" => return Ok(Self::Warning),
                "info" => return Ok(Self::Info),
                _ => {}
            }
        }
        // Try to extract as integer (by discriminant value)
        if let Ok(n) = value.extract::<i32>() {
            match n {
                0 => return Ok(Self::Error),
                1 => return Ok(Self::Warning),
                2 => return Ok(Self::Info),
                _ => {}
            }
        }
        let type_name = stringify!(DiagnosticSeverity);
        Err(pyo3::exceptions::PyValueError::new_err(format!(
            "invalid value for {}: {:#?}. Expected variant name (str) or discriminant (int)",
            type_name, value
        )))
    }

    fn __str__(&self) -> PyResult<String> {
        serde_json::to_value(self)
            .map(|value| match value {
                serde_json::Value::String(value) => value,
                other => other.to_string(),
            })
            .map_err(|e| {
                pyo3::exceptions::PyRuntimeError::new_err(format!("Failed to serialize DiagnosticSeverity: {e}"))
            })
    }

    fn __repr__(&self) -> PyResult<String> {
        self.__str__()
    }
}

