// Error types
pyo3::create_exception!(_native, LanguageNotFoundError, pyo3::exceptions::PyException);
pyo3::create_exception!(_native, DynamicLoadError, pyo3::exceptions::PyException);
pyo3::create_exception!(_native, NullLanguagePointerError, pyo3::exceptions::PyException);
pyo3::create_exception!(_native, ParserSetupError, pyo3::exceptions::PyException);
pyo3::create_exception!(_native, LockPoisonedError, pyo3::exceptions::PyException);
pyo3::create_exception!(_native, ConfigError, pyo3::exceptions::PyException);
pyo3::create_exception!(_native, ParseFailedError, pyo3::exceptions::PyException);
pyo3::create_exception!(_native, QueryError, pyo3::exceptions::PyException);
pyo3::create_exception!(_native, InvalidRangeError, pyo3::exceptions::PyException);
pyo3::create_exception!(_native, DownloadError, pyo3::exceptions::PyException);
pyo3::create_exception!(_native, ChecksumMismatchError, pyo3::exceptions::PyException);
pyo3::create_exception!(_native, CacheLockError, pyo3::exceptions::PyException);
pyo3::create_exception!(_native, Error, pyo3::exceptions::PyException);

/// Convert a `tree_sitter_language_pack::Error` error to a Python exception.
fn error_to_py_err(e: tree_sitter_language_pack::Error) -> pyo3::PyErr {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        tree_sitter_language_pack::Error::LanguageNotFound(..) => LanguageNotFoundError::new_err(msg),
        tree_sitter_language_pack::Error::DynamicLoad(..) => DynamicLoadError::new_err(msg),
        tree_sitter_language_pack::Error::NullLanguagePointer(..) => NullLanguagePointerError::new_err(msg),
        tree_sitter_language_pack::Error::ParserSetup(..) => ParserSetupError::new_err(msg),
        tree_sitter_language_pack::Error::LockPoisoned(..) => LockPoisonedError::new_err(msg),
        tree_sitter_language_pack::Error::Config(..) => ConfigError::new_err(msg),
        tree_sitter_language_pack::Error::ParseFailed => ParseFailedError::new_err(msg),
        tree_sitter_language_pack::Error::QueryError(..) => QueryError::new_err(msg),
        tree_sitter_language_pack::Error::InvalidRange(..) => InvalidRangeError::new_err(msg),
        tree_sitter_language_pack::Error::Download(..) => DownloadError::new_err(msg),
        tree_sitter_language_pack::Error::ChecksumMismatch { .. } => ChecksumMismatchError::new_err(msg),
        tree_sitter_language_pack::Error::CacheLock(..) => CacheLockError::new_err(msg),
        _ => Error::new_err(msg),
    }
}

